## Summary

OpenClaw の DiagnosticEvent を参考に、実行状況のモニタリング用に専用の診断イベントシステムを追加する。モニタリング、アラート発報、デバッグに活用できる。

## 変更内容

### 1. 診断イベント型定義 (`src/core/diagnostic-events.ts`) - 新規ファイル

```typescript
export type DiagnosticEventPayload =
  | { type: "run.attempt"; run_id: string; job_name: string; attempt: number }
  | { type: "run.stuck"; job_name: string; age_ms: number; last_status: string }
  | { type: "queue.depth"; depth: number; max: number }
  | { type: "agent.timeout"; policy_name: string; event_id: string; duration_ms: number }
  | { type: "event.dropped"; event_id: string; reason: "recursion" | "context_key" }
  | { type: "system.heartbeat"; active_runs: number; pending_events: number };

export type DiagnosticListener = (evt: DiagnosticEventPayload & { ts: number }) => void;
```

### 2. グローバル診断イベントバス

```typescript
// シングルトンパターン
type DiagnosticEventsState = {
  seq: number;
  listeners: Set<DiagnosticListener>;
  dispatchDepth: number;
};

function getDiagnosticEventsState(): DiagnosticEventsState {
  // globalThis に保存してプロセス内で共有
}

export function emitDiagnosticEvent(event: DiagnosticEventPayload): void {
  const state = getDiagnosticEventsState();
  const enriched = { ...event, ts: Date.now() };

  for (const listener of state.listeners) {
    try {
      listener(enriched);
    } catch {
      // リスナーエラーは握りつぶし
    }
  }
}

export function onDiagnosticEvent(listener: DiagnosticListener): () => void {
  const state = getDiagnosticEventsState();
  state.listeners.add(listener);
  return () => state.listeners.delete(listener);
}
```

### 3. 既存コードへの発行箇所追加

```typescript
// executor.ts
this.logger.info({ job: jobName, run_id: runId }, "ジョブ実行開始");
emitDiagnosticEvent({ type: "run.attempt", run_id: runId, job_name: jobName, attempt: 1 });

// event-bus.ts
if (this.dispatchDepth >= this.maxDispatchDepth) {
  emitDiagnosticEvent({ type: "event.dropped", event_id: event.event_id, reason: "recursion" });
  return;
}
```

